const items = $input.all();
const dayAgoMs = Date.now() - 24 * 60 * 60 * 1000;
const ON_THRESHOLD_W = 5; // fallback only, used when no switch entity exists (BitAxe #1 lottery)

const toPoints = (entries) => entries
  .map((e) => ({ t: new Date(e.last_changed).getTime(), state: e.state }))
  .filter((p) => Number.isFinite(p.t))
  .sort((a, b) => a.t - b.t);

const dayFilter = (points) => points.filter((p) => p.t >= dayAgoMs);

const integrateKWh = (points) => {
  let wattSeconds = 0;
  for (let i = 1; i < points.length; i++) {
    const w0 = parseFloat(points[i - 1].state);
    const w1 = parseFloat(points[i].state);
    if (!Number.isFinite(w0) || !Number.isFinite(w1)) continue;
    const dtSeconds = (points[i].t - points[i - 1].t) / 1000;
    wattSeconds += ((w0 + w1) / 2) * dtSeconds;
  }
  return wattSeconds / 3600000; // Ws -> kWh
};

const wattThresholdRuntimeHours = (points) => {
  let seconds = 0;
  for (let i = 1; i < points.length; i++) {
    const w0 = parseFloat(points[i - 1].state);
    if (Number.isFinite(w0) && w0 > ON_THRESHOLD_W) {
      seconds += (points[i].t - points[i - 1].t) / 1000;
    }
  }
  return seconds / 3600;
};

const switchRuntimeHours = (points) => {
  let seconds = 0;
  for (let i = 1; i < points.length; i++) {
    if (points[i - 1].state === 'on') {
      seconds += (points[i].t - points[i - 1].t) / 1000;
    }
  }
  return seconds / 3600;
};

const BRAIINS_ENTITY_IDS = [
  'sensor.miner_avalon_nano_3s_leistung',
  'sensor.miner_avalon_nano_3s_2_leistung',
  'sensor.bitaxe2_power'
];
const LOTTERY_ENTITY_IDS = ['sensor.bitaxe1_power'];

// Which switch entity gates which power sensor's real runtime
const SWITCH_FOR_SENSOR = {
  'sensor.miner_avalon_nano_3s_leistung': 'switch.grow_inbox_socket_2',
  'sensor.miner_avalon_nano_3s_2_leistung': 'switch.grow_inbox_socket_1',
  'sensor.bitaxe2_power': 'switch.sonoff_schalter'
};

const raw = {};
for (const item of items) {
  const data = item.json;
  const entries = Array.isArray(data) ? data : (Array.isArray(data?.data) ? data.data : []);
  const entityId = entries[0]?.entity_id;
  if (!entityId) continue;
  raw[entityId] = toPoints(entries);
}

const powerSensorIds = [...BRAIINS_ENTITY_IDS, ...LOTTERY_ENTITY_IDS];
const minerResults = powerSensorIds.map((entityId) => {
  const points = raw[entityId] || [];
  const dayPoints = dayFilter(points);
  const pool = BRAIINS_ENTITY_IDS.includes(entityId) ? 'braiins' : 'lottery';

  const switchEntityId = SWITCH_FOR_SENSOR[entityId];
  const switchPoints = switchEntityId ? (raw[switchEntityId] || []) : [];
  const daySwitchPoints = dayFilter(switchPoints);

  const runtimeHours24h = switchEntityId ? switchRuntimeHours(daySwitchPoints) : wattThresholdRuntimeHours(dayPoints);
  const runtimeHours7d = switchEntityId ? switchRuntimeHours(switchPoints) : wattThresholdRuntimeHours(points);

  return {
    entityId,
    pool,
    kWh24h: integrateKWh(dayPoints),
    kWh7d: integrateKWh(points),
    runtimeHours24h,
    runtimeHours7d,
    runtimeSource: switchEntityId ? switchEntityId : 'watt-threshold'
  };
});

const sumBy = (arr, key) => arr.reduce((sum, m) => sum + m[key], 0);
const braiinsMiners = minerResults.filter((m) => m.pool === 'braiins');
const lotteryMiners = minerResults.filter((m) => m.pool === 'lottery');

const latestState = (entityId) => {
  const points = raw[entityId] || [];
  return points.length ? points[points.length - 1].state : null;
};

return [{
  json: {
    perMiner: minerResults,
    braiins: {
      kWh24h: sumBy(braiinsMiners, 'kWh24h'),
      kWh7d: sumBy(braiinsMiners, 'kWh7d')
    },
    lottery: {
      kWh24h: sumBy(lotteryMiners, 'kWh24h'),
      kWh7d: sumBy(lotteryMiners, 'kWh7d')
    },
    modes: {
      avalon1: latestState('select.miner_avalon_nano_3s_arbeitsmodus'),
      avalon2: latestState('select.miner_avalon_nano_3s_2_arbeitsmodus')
    }
  }
}];

const energy = $('Calculate Energy Consumption (kWh)').first().json;
const profileRaw = $('Get Braiins Profile').first().json;
const rewardsRaw = $('Get Braiins Daily Rewards').first().json;
const priceRaw = $('Get BTC Price').first().json;
const lotteryRaw = $('Get Powermining Lottery Stats').first().json;
const networkRaw = $('Get Network Difficulty').first().json;
const oceanRaw = $('Parse Ocean Stats').first().json;
const feedInRaw = $('Parse Feed-in Tariff').first().json;

const profile = profileRaw.btc ?? profileRaw;
const rewardsList = Array.isArray(rewardsRaw)
  ? rewardsRaw
  : (rewardsRaw.btc?.daily_rewards ?? rewardsRaw.daily_rewards ?? []);

const btcPriceEur = priceRaw?.bitcoin?.eur ?? 0;
// Opportunity cost, not a real cash cost: this is the aWATTar SUNNY feed-in tariff you'd
// have earned by exporting this solar surplus instead of using it to mine.
const feedInTariffEurPerKWh = feedInRaw?.feedInTariffEurPerKWh ?? 0.1349;
const toNum = (v) => parseFloat(v) || 0;
const toSats = (btc) => Math.round((btc ?? 0) * 1e8);

// --- Day (rolling 24h) -- Braiins-Miner: Avalon #1+#2, BitAxe #2 ---
const dayKWh = energy.braiins.kWh24h;
const dayForegoneFeedInEur = dayKWh * feedInTariffEurPerKWh;
const dayRewardBtc = toNum(profile.today_reward);
const dayRewardSats = toSats(dayRewardBtc);
const dayEarningsEur = dayRewardBtc * btcPriceEur;
const dayAdvantageEur = dayEarningsEur - dayForegoneFeedInEur;
const dayRoiPct = dayForegoneFeedInEur > 0 ? (dayAdvantageEur / dayForegoneFeedInEur) * 100 : null;

// --- Week (rolling 7 days) ---
const weekKWh = energy.braiins.kWh7d;
const weekForegoneFeedInEur = weekKWh * feedInTariffEurPerKWh;
const last7 = rewardsList.slice(0, 7);
const weekRewardBtc = last7.reduce((sum, entry) => sum + toNum(entry.total_reward), 0);
const weekRewardSats = toSats(weekRewardBtc);
const weekEarningsEur = weekRewardBtc * btcPriceEur;
const weekAdvantageEur = weekEarningsEur - weekForegoneFeedInEur;
const weekRoiPct = weekForegoneFeedInEur > 0 ? (weekAdvantageEur / weekForegoneFeedInEur) * 100 : null;

// --- Year projection (365 days), based on the last 7 days' daily average ---
const avgDailyKWh = weekKWh / 7;
const avgDailyRewardBtc = weekRewardBtc / 7;
const yearKWh = avgDailyKWh * 365;
const yearForegoneFeedInEur = yearKWh * feedInTariffEurPerKWh;
const yearRewardBtc = avgDailyRewardBtc * 365;

const scenario = (priceMultiplier) => {
  const price = btcPriceEur * priceMultiplier;
  const earnings = yearRewardBtc * price;
  const advantage = earnings - yearForegoneFeedInEur;
  return {
    btcPriceEur: price,
    earningsEur: earnings,
    profitEur: advantage,
    roiPct: yearForegoneFeedInEur > 0 ? (advantage / yearForegoneFeedInEur) * 100 : null
  };
};

// --- Lottery-Miner: BitAxe #1, solo auf pool.powermining.io ---
const networkDifficulty = networkRaw?.difficulty ?? 0;
const lotteryBestDifficulty = toNum(lotteryRaw?.bestDifficulty);
const lotteryKWh24h = energy.lottery.kWh24h;
const lotteryKWh7d = energy.lottery.kWh7d;
const lotteryBlockFound = networkDifficulty > 0 && lotteryBestDifficulty >= networkDifficulty;
const lotteryDifficultyRatio = lotteryBestDifficulty > 0 ? networkDifficulty / lotteryBestDifficulty : null;
const currentBlockSubsidyBtc = 3.125;

// --- Braiins Konto insgesamt ---
const allTimeRewardBtc = toNum(profile.all_time_reward);
const accountBalanceBtc = toNum(profile.current_balance);
// all_time_reward = everything ever earned (paid + still pending); current_balance = still pending/unpaid.
// So what has actually been paid out to the wallet so far is the difference.
const paidOutBtc = Math.max(0, allTimeRewardBtc - accountBalanceBtc);
const paidOutEur = paidOutBtc * btcPriceEur;

return [{
  json: {
    assumptions: {
      feedInTariffEurPerKWh,
      feedInTariffCentPerKWh: feedInRaw?.feedInTariffCentPerKWh ?? null,
      btcPriceEur,
      note: 'Kosten = entgangene Einspeiseverguetung (aWATTar SUNNY Tarif), NICHT der Netzbezugspreis, da die Miner nur PV-Ueberschuss nutzen. Jahresprognose basiert auf dem Tagesdurchschnitt der letzten 7 Tage (nur Braiins-Miner: Avalon #1+#2, BitAxe #2), hochgerechnet auf 365 Tage. Keine Saisonalitaet beruecksichtigt. BitAxe #2 laeuft zeitweise auf Ocean statt Braiins - dessen kWh sind hier trotzdem komplett der Braiins-Zeile zugerechnet, da der genaue zeitliche Split nicht bekannt ist.'
    },
    braiinsAccountTotal: {
      allTimeRewardSats: toSats(allTimeRewardBtc),
      allTimeRewardBtc,
      currentBalanceSats: toSats(accountBalanceBtc),
      currentBalanceBtc: accountBalanceBtc,
      paidOutSats: toSats(paidOutBtc),
      paidOutBtc,
      paidOutEur
    },
    day: { kWh: dayKWh, costEur: dayForegoneFeedInEur, rewardSats: dayRewardSats, rewardBtc: dayRewardBtc, earningsEur: dayEarningsEur, profitEur: dayAdvantageEur, roiPct: dayRoiPct },
    week: { kWh: weekKWh, costEur: weekForegoneFeedInEur, rewardSats: weekRewardSats, rewardBtc: weekRewardBtc, earningsEur: weekEarningsEur, profitEur: weekAdvantageEur, roiPct: weekRoiPct },
    year: {
      kWh: yearKWh,
      costEur: yearForegoneFeedInEur,
      rewardBtc: yearRewardBtc,
      rewardSats: toSats(yearRewardBtc),
      scenarios: { bearish: scenario(0.7), base: scenario(1.0), bullish: scenario(1.3) }
    },
    lottery: {
      note: 'BitAxe #1 minted solo auf pool.powermining.io - kein laufender Ertrag, nur Blockchance.',
      address: 'bc1qfm6wv0ggw00df2lqc8ck27aansztsrv8k3lw22',
      kWh24h: lotteryKWh24h,
      kWh7d: lotteryKWh7d,
      costEur24h: lotteryKWh24h * feedInTariffEurPerKWh,
      costEur7d: lotteryKWh7d * feedInTariffEurPerKWh,
      bestDifficultyEver: lotteryBestDifficulty,
      networkDifficulty,
      blockFound: lotteryBlockFound,
      difficultyRatio: lotteryDifficultyRatio,
      potentialBlockValueEur: currentBlockSubsidyBtc * btcPriceEur
    },
    oceanBitaxe2: {
      note: 'BitAxe #2 laeuft zeitweise auf mine.ocean.xyz statt Braiins - zusaetzlich zur Braiins-Zeile. Nur der verifizierte Wert (bisher aufgelaufen/unbezahlt) wird gezeigt, die anderen Ocean-Felder waren nicht zuverlaessig auslesbar.',
      address: 'bc1qfm6wv0ggw00df2lqc8ck27aansztsrv8k3lw22',
      unpaidEarningsSats: toSats(oceanRaw.unpaidEarningsBtc)
    },
    modes: energy.modes,
    perMiner: energy.perMiner
  }
}];

const extractBtc = (html, label) => {
  const escaped = label.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
  const re = new RegExp(escaped + '[\\s\\S]{0,400}?<span>\\s*([0-9.]+)\\s*BTC<\\/span>', 'i');
  const m = html.match(re);
  return m ? parseFloat(m[1]) : null;
};

const html = $input.first().json.data ?? '';

return [{
  json: {
    estimatedRewardsInWindowBtc: extractBtc(html, 'Estimated Rewards In Window'),
    estimatedEarningsNextBlockBtc: extractBtc(html, 'Estimated Earnings Next Block'),
    estimatedEarningsPerDayBtc: extractBtc(html, 'Estimated Earnings Per Day'),
    lifetimeEarningsBtc: extractBtc(html, 'Lifetime Earnings'),
    unpaidEarningsBtc: extractBtc(html, 'Unpaid Earnings'),
    estimatedPayoutNextBlockBtc: extractBtc(html, 'Estimated Payout Next Block')
  }
}];

const r = $input.first().json;
const fmtEur = (n) => (n ?? 0).toLocaleString('de-DE', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ' EUR';
const fmtSats = (n) => (n ?? 0).toLocaleString('de-DE') + ' Sats';
const fmtKwh = (n) => (n ?? 0).toLocaleString('de-DE', { minimumFractionDigits: 2, maximumFractionDigits: 2 }) + ' kWh';
const fmtH = (n) => (n ?? 0).toLocaleString('de-DE', { minimumFractionDigits: 1, maximumFractionDigits: 1 }) + ' h';
const fmtPct = (n) => (n === null || n === undefined) ? '-' : n.toLocaleString('de-DE', { minimumFractionDigits: 1, maximumFractionDigits: 1 }) + ' %';
const advClass = (n) => (n ?? 0) >= 0 ? 'pos' : 'neg';
const tariff = r.assumptions.feedInTariffCentPerKWh ?? '?';

const minerRows = r.perMiner.map((m) => `
  <tr>
    <td>${m.entityId}</td>
    <td>${m.pool === 'braiins' ? 'Braiins' : 'Lottery'}</td>
    <td>${fmtKwh(m.kWh24h)}</td>
    <td>${fmtH(m.runtimeHours24h)}</td>
    <td>${fmtKwh(m.kWh7d)}</td>
    <td>${fmtH(m.runtimeHours7d)}</td>
  </tr>`).join('');

const compareRow = (label, period) => `
  <tr>
    <td>${label}</td>
    <td>${fmtKwh(period.kWh)}</td>
    <td>${fmtEur(period.costEur)}</td>
    <td>${fmtSats(period.rewardSats)}<br><span class="note" style="margin:0">${fmtEur(period.earningsEur)}</span></td>
    <td class="${advClass(period.profitEur)}">${fmtEur(period.profitEur)}</td>
  </tr>`;

const html = `<!DOCTYPE html>
<html lang="de">
<head>
<meta charset="utf-8">
<meta name="viewport" content="width=device-width, initial-scale=1">
<title>Solar Mining ROI Dashboard</title>
<style>
  :root { color-scheme: dark; }
  body { font-family: -apple-system, Segoe UI, Roboto, Arial, sans-serif; background: #0f1115; color: #e6e8eb; margin: 0; padding: 24px; }
  .wrap { max-width: 960px; margin: 0 auto; }
  h1 { font-size: 1.6rem; margin-bottom: 4px; }
  .sub { color: #8a93a3; margin-bottom: 24px; font-size: 0.9rem; }
  .card { background: #171a21; border: 1px solid #262b36; border-radius: 12px; padding: 20px; margin-bottom: 20px; }
  .card h2 { margin-top: 0; font-size: 1.15rem; }
  table { width: 100%; border-collapse: collapse; margin-top: 8px; }
  th, td { text-align: left; padding: 8px 10px; border-bottom: 1px solid #262b36; font-size: 0.88rem; vertical-align: top; }
  th { color: #8a93a3; font-weight: 600; }
  .pos { color: #4ade80; font-weight: 600; }
  .neg { color: #f87171; font-weight: 600; }
  .grid3 { display: grid; grid-template-columns: repeat(3, 1fr); gap: 16px; }
  @media (max-width: 700px) { .grid3 { grid-template-columns: 1fr; } table { display: block; overflow-x: auto; white-space: nowrap; } }
  .stat { background: #12151b; border-radius: 8px; padding: 14px; }
  .stat .label { color: #8a93a3; font-size: 0.75rem; text-transform: uppercase; letter-spacing: .04em; }
  .stat .value { font-size: 1.3rem; font-weight: 700; margin-top: 4px; }
  .note { color: #8a93a3; font-size: 0.85rem; margin-top: 10px; }
  .pill { display: inline-block; padding: 2px 10px; border-radius: 999px; font-size: 0.75rem; font-weight: 600; vertical-align: middle; margin-left: 8px; }
  .pill.found { background: rgba(74,222,128,0.2); color: #4ade80; }
  .pill.notfound { background: rgba(248,113,113,0.2); color: #f87171; }
  code { background: #12151b; padding: 2px 6px; border-radius: 4px; font-size: 0.82rem; }
</style>
</head>
<body>
<div class="wrap">
  <h1>Solar Mining ROI Dashboard</h1>
  <div class="sub">Stand: ${new Date().toLocaleString('de-DE')} &middot; Einspeiseverguetung (aWATTar SUNNY, live): ${tariff} Cent/kWh &middot; BTC-Kurs (live): ${fmtEur(r.assumptions.btcPriceEur)}</div>

  <div class="card">
    <h2>Braiins-Miner (Avalon #1+#2, BitAxe #2)</h2>
    <div class="grid3">
      <div class="stat"><div class="label">Ausbezahlt (all-time)</div><div class="value">${fmtSats(r.braiinsAccountTotal.paidOutSats)}</div><div class="note">${fmtEur(r.braiinsAccountTotal.paidOutEur)} zum aktuellen Kurs</div></div>
      <div class="stat"><div class="label">Aktuell unbezahlt</div><div class="value">${fmtSats(r.braiinsAccountTotal.currentBalanceSats)}</div></div>
      <div class="stat"><div class="label">Insgesamt verdient (all-time)</div><div class="value">${fmtSats(r.braiinsAccountTotal.allTimeRewardSats)}</div></div>
    </div>
    <div class="note" style="margin-top:16px;">"Einspeisung waere gewesen" = PV-kWh x aktueller aWATTar-Tarif. "Mining-Ertrag" = Sats x aktueller BTC-Kurs. Beides wird bei jedem Aufruf frisch geholt.</div>
    <table>
      <tr><th></th><th>PV-Strom genutzt</th><th>Einspeisung waere gewesen<br><small>bei ${tariff} Cent/kWh</small></th><th>Mining hat eingebracht<br><small>bei aktuellem BTC-Kurs</small></th><th>Differenz</th></tr>
      ${compareRow('Heute (24h)', r.day)}
      ${compareRow('Woche (7 Tage)', r.week)}
      ${compareRow('Jahr (Prognose, base)', { kWh: r.year.kWh, costEur: r.year.costEur, rewardSats: r.year.rewardSats, earningsEur: r.year.scenarios.base.earningsEur, profitEur: r.year.scenarios.base.profitEur })}
    </table>
    <div class="note" style="margin-top:16px;">Jahresprognose bei anderem BTC-Kurs (Sats-Menge bleibt gleich, nur der Kurs aendert sich):</div>
    <table>
      <tr><th>Szenario</th><th>BTC-Kurs</th><th>Mining hat eingebracht</th><th>Differenz zur Einspeisung</th><th>%</th></tr>
      <tr><td>Bearish (-30%)</td><td>${fmtEur(r.year.scenarios.bearish.btcPriceEur)}</td><td>${fmtEur(r.year.scenarios.bearish.earningsEur)}</td><td class="${advClass(r.year.scenarios.bearish.profitEur)}">${fmtEur(r.year.scenarios.bearish.profitEur)}</td><td>${fmtPct(r.year.scenarios.bearish.roiPct)}</td></tr>
      <tr><td>Base</td><td>${fmtEur(r.year.scenarios.base.btcPriceEur)}</td><td>${fmtEur(r.year.scenarios.base.earningsEur)}</td><td class="${advClass(r.year.scenarios.base.profitEur)}">${fmtEur(r.year.scenarios.base.profitEur)}</td><td>${fmtPct(r.year.scenarios.base.roiPct)}</td></tr>
      <tr><td>Bullish (+30%)</td><td>${fmtEur(r.year.scenarios.bullish.btcPriceEur)}</td><td>${fmtEur(r.year.scenarios.bullish.earningsEur)}</td><td class="${advClass(r.year.scenarios.bullish.profitEur)}">${fmtEur(r.year.scenarios.bullish.profitEur)}</td><td>${fmtPct(r.year.scenarios.bullish.roiPct)}</td></tr>
    </table>
  </div>

  <div class="card">
    <h2>Lottery-Check: BitAxe #1<span class="pill ${r.lottery.blockFound ? 'found' : 'notfound'}">${r.lottery.blockFound ? 'BLOCK GEFUNDEN!' : 'Kein Block'}</span></h2>
    <div class="note">Solo auf pool.powermining.io &middot; Adresse <code>${r.lottery.address}</code></div>
    <div class="grid3">
      <div class="stat"><div class="label">Beste Difficulty (all-time)</div><div class="value">${Math.round(r.lottery.bestDifficultyEver).toLocaleString('de-DE')}</div></div>
      <div class="stat"><div class="label">Netzwerk-Difficulty</div><div class="value">${Math.round(r.lottery.networkDifficulty).toLocaleString('de-DE')}</div></div>
      <div class="stat"><div class="label">Faktor entfernt</div><div class="value">${r.lottery.difficultyRatio ? Math.round(r.lottery.difficultyRatio).toLocaleString('de-DE') + 'x' : '-'}</div></div>
    </div>
    <div class="note">PV-Strom genutzt: ${fmtKwh(r.lottery.kWh24h)}/Tag, ${fmtKwh(r.lottery.kWh7d)}/Woche (Einspeisung waere gewesen: ${fmtEur(r.lottery.costEur24h)}/${fmtEur(r.lottery.costEur7d)}). Falls Block gefunden: ~${fmtEur(r.lottery.potentialBlockValueEur)}.</div>
  </div>

  <div class="card">
    <h2>Ocean.xyz: BitAxe #2 (zeitweise)</h2>
    <div class="note">Laeuft manchmal zusaetzlich auf mine.ocean.xyz statt Braiins &middot; Adresse <code>${r.oceanBitaxe2.address}</code> &middot; zusaetzlich zur Braiins-Zeile oben</div>
    <div class="stat" style="max-width: 260px;"><div class="label">Bisher aufgelaufen (unbezahlt)</div><div class="value">${fmtSats(r.oceanBitaxe2.unpaidEarningsSats)}</div></div>
  </div>

  <div class="card">
    <h2>Miner im Detail</h2>
    <table>
      <tr><th>Entity</th><th>Pool</th><th>kWh 24h</th><th>Laufzeit 24h</th><th>kWh 7d</th><th>Laufzeit 7d</th></tr>
      ${minerRows}
    </table>
    <div class="note">Arbeitsmodus Avalon #1: <code>${r.modes.avalon1 ?? '-'}</code> &middot; Avalon #2: <code>${r.modes.avalon2 ?? '-'}</code></div>
    <div class="note">Laufzeiten fuer Avalon #1/#2 und BitAxe #2 stammen aus den Steckdosen-Schaltern (Ein/Aus), BitAxe #1 aus einer Watt-Schwelle (laeuft unkontrolliert durch).</div>
  </div>

  <div class="note">${r.assumptions.note}</div>
</div>
</body>
</html>`;

return [{ json: { html } }];

const html = $input.first().json.data ?? '';
const m = html.match(/([0-9]+,[0-9]+)\s*Cent\/kWh/);
const cent = m ? parseFloat(m[1].replace(',', '.')) : null;

return [{
  json: {
    feedInTariffCentPerKWh: cent,
    feedInTariffEurPerKWh: cent !== null ? cent / 100 : null
  }
}];
